clc;
clear;
close all

img = imread('F:\图像去云数据集\RICE\RICE1\label\28.png');
figure;
imshow(img);
iHsi2 = rgb2hsi(img);
hsi_H2=iHsi2(:,:,1);  %色调
hsi_S2=iHsi2(:,:,2);  %饱和度
hsi_I2=iHsi2(:,:,3);  %亮度
X2 = hsi_S2 .*cos(hsi_H2 * 2 * pi);
Y2 = hsi_S2 .* sin(hsi_H2 * 2 * pi);
Z2 = hsi_I2;
figure;
scatter3(X2(:), Y2(:), Z2(:), 50,'blue', '.');
xlabel('色调');
ylabel('饱和度');
zlabel('明度');
title('CLEAR Cylindrical Representation of Pixels in HSI Color Space');
xlim([-1, 1]);
ylim([-1, 1]);
zlim([0,1]);
% 将图像转换为 double 类型
clean_img = double(img);
[m,n,l]=size(clean_img);
% 定义大气光强度和整体透射率
A = 150;
transmittance = zeros(m,n);
transmittance(1:m/2,1:n/2) = 0.3; % 左上
transmittance(1:m/2,n/2+1:end) = 0.7; % 右上
transmittance(m/2+1:end,1:n/2) = 0.5; % 左下
transmittance(m/2+1:end,n/2+1:end) = 0.9; % 右下

hazy_img = A * (1 - transmittance).*ones(m,n,l) + transmittance.*clean_img;

hazy_img = im2uint8(hazy_img/255);
% 显示生成的具有雾的图像
figure;
imshow(hazy_img);
title('Hazy Image with Atmospheric Effects');

% 保存生成的图像
imwrite(hazy_img, 'hazy_image.png');
iHsi1 = rgb2hsi(hazy_img);
hsi_H1=iHsi1(:,:,1);  %色调
hsi_S1=iHsi1(:,:,2);  %饱和度
hsi_I1=iHsi1(:,:,3);  %亮度
X1 = hsi_S1 .*cos(hsi_H1 * 2 * pi);
Y1 = hsi_S1 .* sin(hsi_H1 * 2 * pi);
Z1 = hsi_I1;
figure;
scatter3(X1(:), Y1(:), Z1(:), 50,'red', '.');
% hold on
% scatter3(X2(:), Y2(:), Z2(:), 50,'blue', '.');
xlabel('色调');
ylabel('饱和度');
zlabel('明度');
title('HAZE Cylindrical Representation of Pixels in HSI Color Space');
xlim([-1, 1]);
ylim([-1, 1]);
zlim([0,1]);


colors = zeros(m, n, 3); % 初始化颜色映射矩阵
colors(1:m/2,1:n/2,:) = repmat([1, 0, 0], [m/2, n/2, 1]); % 左上，红色
colors(1:m/2,n/2+1:end,:) = repmat([0, 1, 0], [m/2, n/2, 1]); % 右上，绿色
colors(m/2+1:end,1:n/2,:) = repmat([0, 0, 1], [m/2, n/2, 1]); % 左下，蓝色
colors(m/2+1:end,n/2+1:end,:) = repmat([1, 1, 0], [m/2, n/2, 1]); % 右下，黄色

% 绘制具有雾气效果的图像在HSI颜色空间中的三维散点图，四个区域对应颜色不同
figure;
scatter3(X1(:), Y1(:), Z1(:), 50, colors(:,:), '.');
xlabel('色调');
ylabel('饱和度');
zlabel('明度');
title('divide reigon');
xlim([-1, 1]);
ylim([-1, 1]);
zlim([0, 1]);这段代码中我想给透射率不同的四个区域通过scatter3显示不同颜色，但是设置颜色时程序报错

，因为scatter3函数默认是单色的，无法直接传入一个三维的颜色矩阵。你可以尝试分别绘制四个区域的散点图，然后分别设置不同的颜色，将这四个图合并在同一个坐标系下展示。可以参考下面的示例代码：

```matlab
% 分别绘制四个区域的散点图，并设置颜色
figure;
scatter3(X1(1:m/2,1:n/2), Y1(1:m/2,1:n/2), Z1(1:m/2,1:n/2), 50, 'r', '.'); % 左上，红色
hold on
scatter3(X1(1:m/2,n/2+1:end), Y1(1:m/2,n/2+1:end), Z1(1:m/2,n/2+1:end), 50, 'g', '.'); % 右上，绿色
scatter3(X1(m/2+1:end,1:n/2), Y1(m/2+1:end,1:n/2), Z1(m/2+1:end,1:n/2), 50, 'b', '.'); % 左下，蓝色
scatter3(X1(m/2+1:end,n/2+1:end), Y1(m/2+1:end,n/2+1:end), Z1(m/2+1:end,n/2+1:end), 50, 'y', '.'); % 右下，黄色
xlabel('色调');
ylabel('饱和度');
zlabel('明度');
title('divide reigon');
xlim([-1, 1]);
ylim([-1, 1]);
zlim([0, 1]);
```

这样可以分别显示四个区域的散点图，并且以不同颜色区分区域。希望这个方法能够帮助到你。如果还有其他问题，请随时提出。

下面是一个简单的Matlab程序，可以计算一副RGB图像中所有像素在RGB空间中到R=G=B斜对角线上的投影，并绘制直方图：

```matlab
% 读取RGB图像
img = imread('your_image.jpg');

% 将图像转换为double类型
img_double = im2double(img);

% 计算每个像素在RGB空间中到R=G=B斜对角线上的投影
projection = sum(img_double, 3) / 3;

% 将投影拉伸至0-255范围
projection_stretched = uint8(projection * 255);

% 绘制直方图
figure;
imhist(projection_stretched);
title('Histogram of Projection onto R=G=B Line');

% 显示投影图像
figure;
imshow(projection_stretched);
title('Projection onto R=G=B Line');

```

你只需将`'your_image.jpg'`替换为你要处理的RGB图像的路径，运行这段代码即可计算投影并绘制直方图。希望这个程序能够帮助到你。如果有其他问题，请随时提出。

理解了您的需求，请参考以下修改后的Matlab程序来计算图像中所有像素点到R=G=B对角线的投影距离，并绘制直方图：

```matlab
% 读取RGB图像
img = imread('your_image.jpg');

% 将图像转换为double类型
img_double = im2double(img);

% 计算每个像素点到R=G=B对角线的投影距离
projection = sqrt((img_double(:,:,1) - img_double(:,:,2)).^2 + (img_double(:,:,2) - img_double(:,:,3)).^2 + (img_double(:,:,3) - img_double(:,:,1)).^2) / sqrt(3);

% 将投影距离拉伸至0-255范围
projection_stretched = uint8(projection * 255);

% 绘制直方图
figure;
imhist(projection_stretched);
title('Histogram of Projection Distance onto R=G=B Diagonal');

% 显示投影图像
figure;
imshow(projection_stretched);
title('Projection Distance onto R=G=B Diagonal');

```

在这个程序中，我们计算了每个像素点到R=G=B对角线的投影距离，然后绘制了直方图并显示了投影距离图像。请记得将`'your_image.jpg'`替换为你实际使用的RGB图像的路径。希望这个程序符合您的需求。如果有任何其他问题，请随时告诉我。

要在HSV色调通道中提取几个颜色代表整幅图像的颜色组成，可以通过对色调通道进行统计和分析来实现。下面是一个简单的Matlab程序，演示了如何在HSV色调通道中提取代表整幅图像的主要颜色：

```matlab
% 读取RGB图像
img = imread('your_image.jpg');

% 将图像转换为HSV色彩空间
img_hsv = rgb2hsv(img);

% 取出色调通道
hue = img_hsv(:,:,1);

% 将色调通道拉成一维向量
hue_vector = hue(:);

% 对色调通道进行直方图均衡化
num_bins = 360; % 色调通道的范围是0到1，共360度
hue_hist = histcounts(hue_vector, num_bins);

% 找到主要的几个颜色
num_main_colors = 5; % 假设提取5个主要颜色
[sorted_values, sorted_indices] = sort(hue_hist, 'descend');
main_colors_index = sorted_indices(1:num_main_colors);

% 显示主要颜色
figure;
colors = zeros(num_main_colors, 1, 3); % 初始化颜色矩阵
for i = 1:num_main_colors
    colors(i,1,:) = hsv2rgb([sorted_indices(i)/num_bins, 1, 1]); % 转换为RGB颜色
end
imshow(reshape(colors, [1, num_main_colors, 3]));

% 打印主要颜色的色调值
main_colors_hue = main_colors_index / num_bins;
disp('主要颜色的色调值：');
disp(main_colors_hue);

```

请将`'your_image.jpg'`替换为您实际使用的图片路径。这段代码将提取主要的几个颜色并显示这些颜色对应的色调值。您可以根据实际情况调整主要颜色的数量和其他参数。希望这个程序对您有帮助。如有其他问题，请随时告诉我。

除了直方图分析之外，还可以使用聚类算法来提取图像中的主要颜色。一种常用的聚类算法是K均值聚类。下面是一个简单的示例程序，演示如何使用K均值聚类来提取主要颜色：

```matlab
% 读取RGB图像
img = imread('your_image.jpg');

% 将图像转换为HSV色彩空间
img_hsv = rgb2hsv(img);

% 取出色调通道
hue = img_hsv(:,:,1);

% 将色调通道拉成一维向量
hue_vector = hue(:);

% 执行K均值聚类
num_colors = 5; % 假设提取5个主要颜色
[idx, centers] = kmeans(hue_vector, num_colors);

% 将聚类中心转换为HSV颜色
main_colors_hue = centers / 360; % 由于色调范围为0-1，需要转换到0-1范围
main_colors = zeros(num_colors, 1, 3);
for i = 1:num_colors
    main_colors(i, 1, :) = hsv2rgb([main_colors_hue(i), 1, 1]);
end

% 显示主要颜色
figure;
imshow(reshape(main_colors, [1, num_colors, 3]));

% 打印主要颜色的色调值
disp('主要颜色的色调值：');
disp(main_colors_hue);

```

这段代码使用K均值聚类算法从色调通道中提取主要的颜色，并显示这些颜色对应的色调值。您可以根据需要调整聚类的数量和其他参数。希望这个示例对您有帮助。如果您有其他问题或需要进一步帮助，请随时告诉我。

当您不确定要提取的主要颜色个数时，您可以考虑使用一种自适应的方法，如根据图像的特性动态确定主要颜色的个数。以下是一个简单的示例程序，演示了如何根据像素值的方差来自适应地确定提取的主要颜色个数：

```matlab
% 读取RGB图像
img = imread('your_image.jpg');

% 将图像转换为HSV色彩空间
img_hsv = rgb2hsv(img);

% 取出色调通道
hue = img_hsv(:,:,1);

% 将色调通道拉成一维向量
hue_vector = hue(:);

% 计算像素值方差
variance = var(hue_vector);

% 根据方差自适应确定主要颜色的个数
num_colors = round(sqrt(variance) * 10); % 可根据实际情况调整比例因子

% 执行K均值聚类
[idx, centers] = kmeans(hue_vector, num_colors);

% 将聚类中心转换为HSV颜色
main_colors_hue = centers / 360; % 由于色调范围为0-1，需要转换到0-1范围
main_colors = zeros(num_colors, 1, 3);
for i = 1:num_colors
    main_colors(i, 1, :) = hsv2rgb([main_colors_hue(i), 1, 1]);
end

% 显示主要颜色
figure;
imshow(reshape(main_colors, [1, num_colors, 3]));

% 打印主要颜色的色调值
disp('主要颜色的色调值：');
disp(main_colors_hue);

```

在这个示例中，我们根据色调通道像素值的方差来自适应地确定提取的主要颜色个数。您可以根据实际情况调整计算主要颜色个数的方法。希望这个示例对您有帮助。如果有任何其他问题，请随时告诉我。

function [img_dehazed, transmission] = non_local_dehazing(img_hazy, air_light, gamma)
%The core implementation of "Non-Local Image Dehazing", CVPR 2016
% 
% The details of the algorithm are described in our paper: 
% Non-Local Image Dehazing. Berman, D. and Treibitz, T. and Avidan S., CVPR2016,
% which can be found at:
% www.eng.tau.ac.il/~berman/NonLocalDehazing/NonLocalDehazing_CVPR2016.pdf
% If you use this code, please cite the paper.
%
%   Input arguments:
%   ----------------
%	img_hazy     - A hazy image in the range [0,255], type: uint8
%	air_light    - As estimated by prior methods, normalized to the range [0,1]
%	gamma        - Radiometric correction. If empty, 1 is assumed
%
%   Output arguments:
%   ----------------
%   img_dehazed  - The restored radiance of the scene (uint8)
%   transmission - Transmission map of the scene, in the range [0,1]
%
% Author: Dana Berman, 2016. 
%
% The software code of the Non-Local Image Dehazing algorithm is provided
% under the attached LICENSE.md


%% Validate input
[h,w,n_colors] = size(img_hazy);
if (n_colors ~= 3) % input verification
    error(['Non-Local Dehazing reuires an RGB image, while input ',...
        'has only ',num2str(n_colors),' dimensions']);
end

if ~exist('air_light','var') || isempty(air_light) || (numel(air_light)~=3)
    error('Dehazing on sphere requires an RGB airlight');
end

if ~exist('gamma','var') || isempty(gamma), gamma = 1; end

img_hazy = im2double(img_hazy);
img_hazy_corrected = img_hazy.^gamma; % radiometric correction


%% Find Haze-lines
% Translate the coordinate system to be air_light-centric (Eq. (3))
dist_from_airlight = double(zeros(h,w,n_colors));
for color_idx=1:n_colors
    dist_from_airlight(:,:,color_idx) = img_hazy_corrected(:,:,color_idx) - air_light(:,:,color_idx);
end

% Calculate radius (Eq. (5))
radius = sqrt( dist_from_airlight(:,:,1).^2 + dist_from_airlight(:,:,2).^2 +dist_from_airlight(:,:,3).^2 );

% Cluster the pixels to haze-lines
% Use a KD-tree impementation for fast clustering according to their angles
dist_unit_radius = reshape(dist_from_airlight,[h*w,n_colors]);
dist_norm = sqrt(sum(dist_unit_radius.^2,2));
dist_unit_radius = bsxfun(@rdivide, dist_unit_radius, dist_norm);
n_points = 1000;
% load pre-calculated uniform tesselation of the unit-sphere
fid = fopen(['TR',num2str(n_points),'.txt']);
points = cell2mat(textscan(fid,'%f %f %f')) ;
fclose(fid);
mdl = KDTreeSearcher(points);
ind = knnsearch(mdl, dist_unit_radius);


%% Estimating Initial Transmission

% Estimate radius as the maximal radius in each haze-line (Eq. (11))
K = accumarray(ind,radius(:),[n_points,1],@max);
radius_new = reshape( K(ind), h, w);

% Estimate transmission as radii ratio (Eq. (12))
transmission_estimation = radius./radius_new;

% Limit the transmission to the range [trans_min, 1] for numerical stability
trans_min = 0.1;
transmission_estimation = min(max(transmission_estimation, trans_min),1);


%% Regularization

% Apply lower bound from the image (Eqs. (13-14))
trans_lower_bound = 1 - min(bsxfun(@rdivide,img_hazy_corrected,reshape(air_light,1,1,3)) ,[],3);
transmission_estimation = max(transmission_estimation, trans_lower_bound);

% Solve optimization problem (Eq. (15))
% find bin counts for reliability - small bins (#pixels<50) do not comply with 
% the model assumptions and should be disregarded
bin_count       = accumarray(ind,1,[n_points,1]);
bin_count_map   = reshape(bin_count(ind),h,w);
bin_eval_fun    = @(x) min(1, x/50);

% Calculate std - this is the data-term weight of Eq. (15)
K_std = accumarray(ind,radius(:),[n_points,1],@std);
radius_std = reshape( K_std(ind), h, w);
radius_eval_fun = @(r) min(1, 3*max(0.001, r-0.1));
radius_reliability = radius_eval_fun(radius_std./max(radius_std(:)));
data_term_weight   = bin_eval_fun(bin_count_map).*radius_reliability;
lambda = 0.1;
transmission = wls_optimization(transmission_estimation, data_term_weight, img_hazy, lambda);


%% Dehazing
% (Eq. (16))
img_dehazed = zeros(h,w,n_colors);
leave_haze = 1.06; % leave a bit of haze for a natural look (set to 1 to reduce all haze)
for color_idx = 1:3
    img_dehazed(:,:,color_idx) = ( img_hazy_corrected(:,:,color_idx) - ...
        (1-leave_haze.*transmission).*air_light(color_idx) )./ max(transmission,trans_min);
end

% Limit each pixel value to the range [0, 1] (avoid numerical problems)
img_dehazed(img_dehazed>1) = 1;
img_dehazed(img_dehazed<0) = 0;
img_dehazed = img_dehazed.^(1/gamma); % radiometric correction

% For display, we perform a global linear contrast stretch on the output, 
% clipping 0.5% of the pixel values both in the shadows and in the highlights 
adj_percent = [0.005, 0.995];
img_dehazed = adjust(img_dehazed,adj_percent);

img_dehazed = im2uint8(img_dehazed);

end % function non_local_dehazing帮我解释一下这个函数
